('Powerlifting Competition Simulation',
 'glutes', array['quads','chest','traps'], array['glutes','quads','chest'],
 'strength', 'strength', array['barbell','bench','power_rack'], 'advanced', true,
 'Simulate a full powerlifting competition. Order: Squat (3 attempts in order), Bench (3 attempts), Deadlift (3 attempts). Rest: 3-8 minutes between attempts. Opener: 90% of max. Second: 96-98% of max. Third: either max PR attempt or a solid second number. Full depth on squat, pause on bench, full lockout on deadlift. Calculate: Wilks or DOTS score from total. Competition prep: perform 2-3 weeks before the actual meet.',
 'Openers too heavy leading to misses; no strategy for second and third attempts; insufficient warm-up protocol; mental approach not simulated (nerves are part of competition).',
 'competition_prep', array['Three white lights: make all three attempts count','Opener is your most important attempt: set the tone','Film every attempt: review with coach','Your warm-up is as practiced as your competition attempts'],
 array['Full powerlifting meet entry','Equipped lifting introduction','Raw nationals qualification preparation'],
 array['Individual heavy singles in each lift','Near-max training week at the end of a block','Equipment practice for competition gear'],
 array['powerlifting','competition','simulation','squat','bench','deadlift'], array[],
 'mixed', 'multi', false, 1, null, null, null, true);


