('Thruster (Barbell)',
 'quads', array['glutes','shoulder','triceps','core'], array['quads','glutes','shoulder'],
 'cardio', 'explosive', array['barbell'], 'advanced', true,
 'Front squat + push press in a single fluid movement. Bar in front rack. Squat to full depth. Drive up from the squat and use the momentum to drive bar overhead. Lock out arms. Return bar to front rack as you descend into the next squat. The transition from squat drive to overhead press must be continuous — no re-dip. Used in CrossFit''s "Fran" benchmark (21-15-9 thrusters and pull-ups).',
 'Pausing between squat and press (breaking the movement); bar drifting forward off the front rack; arms bending before full leg extension; descending into squat before the bar is locked out.',
 'conditioning', array['Continuous drive: your legs push the bar all the way overhead','No re-dip: legs to arms is one movement','Front rack: elbows up throughout','Lock out BEFORE you go back down'],
 array['Thruster "Fran" benchmark','Heavy thruster for strength','Dumbbell thruster for unilateral stability'],
 array['Front squat + push press (separated)','Dumbbell thruster lighter','Goblet squat + push press lightweight'],
 array['HIIT','thruster','CrossFit','Fran','conditioning','full_body','barbell'], array['shoulder_impingement','wrist_injury'],
 'explosive', 'sagittal', false, 4, 15, null, 90, true),

